-- Table: zone_flags
CREATE TABLE `zone_flags` (
  `charID` int(11) NOT NULL DEFAULT 0,
  `zoneID` int(11) NOT NULL DEFAULT 0,
  PRIMARY KEY (`charID`,`zoneID`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1;

-- Table: zone_points
CREATE TABLE `zone_points` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `zone` varchar(32) DEFAULT NULL,
  `version` int(11) NOT NULL DEFAULT 0,
  `number` smallint(4) unsigned NOT NULL DEFAULT 1,
  `y` float NOT NULL DEFAULT 0,
  `x` float NOT NULL DEFAULT 0,
  `z` float NOT NULL DEFAULT 0,
  `heading` float NOT NULL DEFAULT 0,
  `target_y` float NOT NULL DEFAULT 0,
  `target_x` float NOT NULL DEFAULT 0,
  `target_z` float NOT NULL DEFAULT 0,
  `target_heading` float NOT NULL DEFAULT 0,
  `zoneinst` smallint(5) unsigned DEFAULT 0,
  `target_zone_id` int(10) unsigned NOT NULL DEFAULT 0,
  `target_instance` int(10) unsigned NOT NULL DEFAULT 0,
  `buffer` float DEFAULT 0,
  `client_version_mask` int(10) unsigned NOT NULL DEFAULT 4294967295,
  `min_expansion` tinyint(4) NOT NULL DEFAULT -1,
  `max_expansion` tinyint(4) NOT NULL DEFAULT -1,
  `content_flags` varchar(100) DEFAULT NULL,
  `content_flags_disabled` varchar(100) DEFAULT NULL,
  `is_virtual` tinyint(4) NOT NULL DEFAULT 0,
  `height` int(11) NOT NULL DEFAULT 0,
  `width` int(11) NOT NULL DEFAULT 0,
  PRIMARY KEY (`id`) USING BTREE,
  KEY `NewIndex` (`number`,`zone`) USING BTREE,
  KEY `zone_points_target_idx` (`target_zone_id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=4520 DEFAULT CHARSET=latin1;

-- Table: zone_state_spawns
CREATE TABLE `zone_state_spawns` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT,
  `zone_id` int(11) unsigned DEFAULT NULL,
  `instance_id` int(11) unsigned DEFAULT NULL,
  `is_corpse` tinyint(11) DEFAULT 0,
  `is_zone` tinyint(11) DEFAULT 0,
  `decay_in_seconds` int(11) DEFAULT 0,
  `npc_id` int(10) unsigned DEFAULT NULL,
  `spawn2_id` int(10) unsigned NOT NULL,
  `spawngroup_id` int(10) unsigned NOT NULL,
  `x` float NOT NULL,
  `y` float NOT NULL,
  `z` float NOT NULL,
  `heading` float NOT NULL,
  `respawn_time` int(10) unsigned NOT NULL,
  `variance` int(10) unsigned NOT NULL,
  `grid` int(10) unsigned DEFAULT 0,
  `current_waypoint` int(11) DEFAULT 0,
  `path_when_zone_idle` smallint(6) DEFAULT 0,
  `condition_id` smallint(5) unsigned DEFAULT 0,
  `condition_min_value` smallint(6) DEFAULT 0,
  `enabled` smallint(6) DEFAULT 1,
  `anim` smallint(5) unsigned DEFAULT 0,
  `loot_data` text DEFAULT NULL,
  `entity_variables` text DEFAULT NULL,
  `buffs` text DEFAULT NULL,
  `hp` bigint(20) DEFAULT 0,
  `mana` bigint(20) DEFAULT 0,
  `endurance` bigint(20) DEFAULT 0,
  `created_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_zone_instance` (`zone_id`,`instance_id`),
  KEY `idx_instance_id` (`instance_id`)
) ENGINE=InnoDB AUTO_INCREMENT=11437 DEFAULT CHARSET=utf8mb4;
